param(
  [string]$ProjectRoot = "F:\1_A_Disk_D\Tool\mcp-plan",
  [switch]$CommitAndPush
)

$ErrorActionPreference = "Stop"

function Fail($message) {
  Write-Host ""
  Write-Host "ERROR: $message" -ForegroundColor Red
  exit 1
}

if (-not (Test-Path $ProjectRoot)) {
  Fail "Project root not found: $ProjectRoot"
}

Set-Location $ProjectRoot

$backendPath = Join-Path $ProjectRoot "apps\backend\server.js"
$uiPath = Join-Path $ProjectRoot "src\features\mcp\McpSessionCompactView.tsx"

if (-not (Test-Path $backendPath)) { Fail "Backend file not found: $backendPath" }
if (-not (Test-Path $uiPath)) { Fail "UI file not found: $uiPath" }

$backupDir = Join-Path $env:TEMP ("mcp-followup-patch-backup-" + (Get-Date -Format "yyyyMMdd-HHmmss"))
New-Item -ItemType Directory -Path $backupDir | Out-Null
Copy-Item $backendPath (Join-Path $backupDir "server.js.bak")
Copy-Item $uiPath (Join-Path $backupDir "McpSessionCompactView.tsx.bak")
Write-Host "Backup outside repo: $backupDir" -ForegroundColor Cyan

$backend = [System.IO.File]::ReadAllText($backendPath, [System.Text.Encoding]::UTF8)

$followupHelpers = @'
function normalizeFollowupPriority(value) {
  const priority = String(value || "medium").trim().toLowerCase() || "medium";
  const allowed = new Set(["low", "medium", "high", "urgent"]);
  if (!allowed.has(priority)) throw badRequest("invalid_priority");
  return priority;
}

async function createMcpSessionCustomerFollowup(body) {
  const sessionCustomerId = String(body.sessionCustomerId || body.session_customer_id || body.id || "").trim();
  if (!sessionCustomerId) throw badRequest("session_customer_id_required");

  const title = String(body.title || body.followupTitle || body.followup_title || "").trim();
  if (!title) throw badRequest("followup_title_required");

  const dueDate = String(body.dueDate || body.due_date || "").trim();
  const priority = normalizeFollowupPriority(body.priority);
  const owner = String(body.owner || "").trim();
  const note = String(body.note || "").trim();
  const followupType = String(body.followupType || body.followup_type || body.type || "general").trim() || "general";

  return supabaseRpc("mcp_create_followup_from_session_customer", {
    p_session_customer_id: sessionCustomerId,
    p_title: title,
    p_due_date: dueDate || null,
    p_priority: priority,
    p_owner: owner || null,
    p_note: note || null,
    p_followup_type: followupType
  });
}

'@

if ($backend -notmatch "function normalizeFollowupPriority") {
  $anchor = "`nfunction randomId(prefix)"
  $index = $backend.IndexOf($anchor)
  if ($index -lt 0) { Fail "Anchor function randomId(prefix) not found" }
  $backend = $backend.Substring(0, $index) + "`n" + $followupHelpers + $backend.Substring($index)
  Write-Host "Inserted backend followup helpers" -ForegroundColor Green
} else {
  Write-Host "Backend followup helpers already exist" -ForegroundColor Yellow
}

$oldRoute = 'if (url.pathname === "/api/mcp-day/session-customer/followup") return wrap(await proxySupabaseFunction("mcp-day-followup", await readJsonBody(req)));'
$newRoute = 'if (url.pathname === "/api/mcp-day/session-customer/followup") return wrap(await createMcpSessionCustomerFollowup(await readJsonBody(req)));'

if ($backend.Contains($oldRoute)) {
  $backend = $backend.Replace($oldRoute, $newRoute)
  Write-Host "Replaced followup route with RPC contract route" -ForegroundColor Green
} elseif ($backend.Contains($newRoute)) {
  Write-Host "Followup RPC route already exists" -ForegroundColor Yellow
} else {
  $anchorRoute = 'if (url.pathname === "/api/mcp-day/session-customer/report") return wrap(await createMcpSessionCustomerReport(await readJsonBody(req)));'
  if (-not $backend.Contains($anchorRoute)) { Fail "Route anchor not found for followup endpoint" }
  $backend = $backend.Replace($anchorRoute, $anchorRoute + "`n  " + $newRoute)
  Write-Host "Inserted followup RPC route" -ForegroundColor Green
}

$utf8NoBom = New-Object System.Text.UTF8Encoding($false)
[System.IO.File]::WriteAllText($backendPath, $backend, $utf8NoBom)

$uiBase64 = ""
$uiBytes = [Convert]::FromBase64String($uiBase64)
[System.IO.File]::WriteAllBytes($uiPath, $uiBytes)
Write-Host "Wrote UI from UTF-8 base64 payload" -ForegroundColor Green

Write-Host ""
Write-Host "Building..." -ForegroundColor Cyan
npm run build
if ($LASTEXITCODE -ne 0) {
  Fail "Build failed. Do not commit/push. Send full build log."
}

Write-Host ""
Write-Host "BUILD OK" -ForegroundColor Green

if ($CommitAndPush) {
  Write-Host ""
  Write-Host "Committing and pushing..." -ForegroundColor Cyan
  git add apps/backend/server.js src/features/mcp/McpSessionCompactView.tsx supabase/migrations/20260705_mcp_followup_from_session_customer_contract.sql
  git commit -m "feat: add MCP followup form flow"
  if ($LASTEXITCODE -ne 0) { Fail "git commit failed. Send git status --short." }
  git push origin main
  if ($LASTEXITCODE -ne 0) { Fail "git push failed. Send log." }
  Write-Host ""
  Write-Host "PUSH DONE. Run pullmcp on VPS after this." -ForegroundColor Green
} else {
  Write-Host ""
  Write-Host "Not committed yet. To commit and push automatically, run:" -ForegroundColor Yellow
  Write-Host 'powershell -ExecutionPolicy Bypass -File .\patch-mcp-followup-flow.ps1 -CommitAndPush' -ForegroundColor Yellow
}
